import{_ as i,o as a,c as e,ag as n}from"./chunks/framework.CbQjVMS6.js";const k=JSON.parse('{"title":"Aliases & Descriptive Names","description":"","frontmatter":{},"headers":[],"relativePath":"features/aliases.md","filePath":"features/aliases.md","lastUpdated":1774323326000}'),t={name:"features/aliases.md"};function l(p,s,h,o,d,r){return a(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="aliases-descriptive-names" tabindex="-1">Aliases &amp; Descriptive Names <a class="header-anchor" href="#aliases-descriptive-names" aria-label="Permalink to &quot;Aliases &amp; Descriptive Names&quot;">​</a></h1><p>With Powerpack you can give your variables, <a href="#lists">lists</a>, “<a href="#goto-labels">goto labels</a>”, <a href="#functions">functions</a> and <a href="#other-code-snippets">other snippets</a> a more descriptive name, which helps make your code clearer and more maintainable.</p><p>Here are some examples:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Give variables better names</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">#define</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> @HighScore</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> H</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">123→</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">@HighScore</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">@HighScore</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">+1→</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">@HighScore</span></span></code></pre></div><p>Everywhere your alias is used, it will be replaced with the text you define. This will be compiled to:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">123→H</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">H+1→H</span></span></code></pre></div><p>Not only is the original code more descriptive and easier to understand — essential in longer programs that use many variables — but also, if you later decide to change the letter used for that variable, you can update it in one place, and it will be updated in every place it’s used.</p><p>By placing all your <code>#define</code> statements at the top of your program, it also provides a helpful list of which variable letters have been used, and you can ensure that you don’t use the same letter again where it might clash and overwrite something you don’t want!</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">#define</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> @HighScore</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> H</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">#define</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> @Counter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> C</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">#define</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> @Level</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> L</span></span></code></pre></div><h2 id="guidelines-for-using-aliases" tabindex="-1">Guidelines for using aliases <a class="header-anchor" href="#guidelines-for-using-aliases" aria-label="Permalink to &quot;Guidelines for using aliases&quot;">​</a></h2><ul><li><p>Aliases are basically a “find and replace”. Powerpack searches through your code and replaces any mentions of an <code>@Alias</code> with its actual value.</p></li><li><p>All aliases must start with the <code>@</code> character and then any combination of letters, numbers or <code>_</code> underscores. Examples:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">@MyVar</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">@AnotherVar2</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">@Highscore_1</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">@Highscore_2</span></span></code></pre></div></li></ul><ul><li>Aliases must be specified on a single line. If you want to put multiple commands into an alias, use the <code>:</code> colon character, like this:<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">#define</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> @MySnippet</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> A→123:Disp A</span></span></code></pre></div></li></ul><ul><li>Using one alias inside another is not thoroughly tested or supported. Do so at your own risk!</li></ul><ul><li><p>If you mistype an alias in your code, Powerpack will give you a warning that it does not exist.</p></li><li><p>If you tend to use the same aliases across multiple files, you can place them in a separate file and use an <a href="./includes"><code>#include</code></a>.</p></li><li><p>You can place a comment on the same line as your alias, and it will be stripped out prior to processing the alias.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">#define</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> @MyAlias</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 123   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// this works fine</span></span></code></pre></div></li><li><p>If your alias has any trailing whitespace (spaces at the end of the line), these are usually stripped out</p></li></ul><hr><p>Aliases are useful not only for simple variables, but other things too:</p><h2 id="lists" tabindex="-1">Lists <a class="header-anchor" href="#lists" aria-label="Permalink to &quot;Lists&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Give my list a better name</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">#define</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> @HighScores</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ⌊H</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{1,2,3}→</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">@HighScores</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Disp </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">@HighScores</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(1)</span></span></code></pre></div><p>This will be compiled to:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{1,2,3}→H</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Disp ⌊H(1)</span></span></code></pre></div><p>(You’ll notice that the optimizer removed the <code>⌊</code> character from the first line, as in this situation the calculator knows it’s a list, and the character is unnecessary.)</p><h2 id="goto-labels" tabindex="-1">Goto labels <a class="header-anchor" href="#goto-labels" aria-label="Permalink to &quot;Goto labels&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Give my labels a better name</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">#define</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> @_Menu</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> M</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Lbl </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">@_Menu</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Goto </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">@_Menu</span></span></code></pre></div><p>This will be compiled to:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Lbl M</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Goto M</span></span></code></pre></div><p>Giving labels a name starting with an underscore can be a helpful way to differentiate them from other things, but this is completely optional.</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><p>If you need to reuse a specific formula in several places within your program, you can store that formula in a <code>Y</code> or <code>r</code> variable and give that a descriptive name.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">#define</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> @RoundTo3Places</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Y₁      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Give formula a name</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;round(X,3)&quot;→</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">@RoundTo3Places</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // Define the formula</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Disp </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">@RoundTo3Places</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(1.12345)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Use the formula wherever needed</span></span></code></pre></div><p>Using an alias for the simple <code>round()</code> example above may be a little overkill, but if your formula becomes quite large and repeatedly used, this can prove very useful.</p><p>The code above will be compiled to:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;round(X,3→Y₁</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Disp Y₁(1.12345</span></span></code></pre></div><p>And should display the result as <code>1.123</code></p><p>The closing quotes and brackets will be stripped by the optimizer since they’re optional.</p><h2 id="other-code-snippets" tabindex="-1">Other code snippets <a class="header-anchor" href="#other-code-snippets" aria-label="Permalink to &quot;Other code snippets&quot;">​</a></h2><p>You can also place longer code snippets into an alias, like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">#define</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> @RunSubProgram</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 123→A:prgmSUBPROG:Disp A</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Run my sub program:</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">@RunSubProgram</span></span></code></pre></div><p>This will be compiled to:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">123→A:prgmSUBPROG:Disp A</span></span></code></pre></div><p>This is useful when you need to repeat a snippet in multiple places and want to have a single place to manage it.</p><h2 id="using-aliases-inside-formulas" tabindex="-1">Using aliases inside formulas <a class="header-anchor" href="#using-aliases-inside-formulas" aria-label="Permalink to &quot;Using aliases inside formulas&quot;">​</a></h2><p>Sometimes you may need to use an alias inside a formula in a way that confuses Powerpack. Here’s an example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">#define</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> @MyVar</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> A</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">1→</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">@MyVar</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">2→B</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Disp </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">@MyVarB</span></span></code></pre></div><p>You might expect this to multiply <code>@MyVar</code> × <code>B</code>, but Powerpack thinks you’re referring to an alias called <code>@MyVarB</code>. To work around this situation, you can wrap your variable in <span><code>{{ double curly braces }}</code></span>, like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">#define</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> @MyVar</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> A</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">1→</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">@MyVar</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">2→B</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Disp {{</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">@MyVar</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}}B</span></span></code></pre></div><p>The above code will be correctly compiled to:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">1→A</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">2→B</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Disp AB</span></span></code></pre></div>`,47)])])}const g=i(t,[["render",l]]);export{k as __pageData,g as default};
